  scorers: [
    {
      name: "query-executes",
      description: "Did the agent produce a successful result without errors?",
      scorer: ({ output }) => (output.success ? 1 : 0),
    },
    {
      name: "answer-contains-expected",
      description: "Does the answer contain all expected substrings?",
