 1→import { ToolLoopAgent, Output, stepCountIs } from "ai";
 2→import { z } from "zod";
 3→import type { Surreal } from "surrealdb";
 4→import type { ChatToolExecutionContext } from "../../chat/tools/types";
 5→import { buildAnalyticsSystemPrompt } from "./prompt";
 6→import { createAnalyticsTools } from "./tools";
 7→
 8→const analyticsResultSchema = z.object({
 9→  answer: z.string().min(1).describe("Human-readable answer to the user's question. Write in natural language, not raw data."),
10→  query_executed: z.string().describe("The SurrealQL query that was executed to obtain the result."),
11→  result_summary: z.string().describe("Brief human-readable summary of the query results, e.g. '3 tasks found' or 'total of 12 features across 2 projects'."),
12→});
13→
14→export type AnalyticsAgentOutput = z.infer<typeof analyticsResultSchema>;
15→
16→export type AnalyticsAgentInput = {
17→  analyticsSurreal: Surreal;
18→  analyticsAgentModel: any;
19→  context: ChatToolExecutionContext;
20→  question: string;
21→};
22→
23→export async function runAnalyticsAgent(input: AnalyticsAgentInput): Promise<AnalyticsAgentOutput> {
24→  const system = buildAnalyticsSystemPrompt();
25→
26→  const agent = new ToolLoopAgent({
27→    id: "analytics-agent",
28→    model: input.analyticsAgentModel,
29→    instructions: system,
30→    tools: createAnalyticsTools(input.analyticsSurreal),
31→    output: Output.object({ schema: analyticsResultSchema }),
32→    experimental_context: input.context,
33→    stopWhen: stepCountIs(5),
34→  });
35→
36→  const result = await agent.generate({
37→    prompt: input.question,
38→  });
39→
40→  if (!result.output) {
41→    throw new Error("analytics agent did not produce structured output");
42→  }
43→
44→  console.log("[analytics] answer:", result.output.answer);
45→  console.log("[analytics] result_summary:", result.output.result_summary);
46→
47→  return result.output;
48→}
