 42→export function ChatPage() {
 43→  const onboardingState = useWorkspaceState((s) => s.onboardingState);
 44→  const setSidebarHandlers = useWorkspaceState((s) => s.setSidebarHandlers);
 45→
 46→  const chat = useChatSession();
 47→
 48→  // Keep a ref to the latest chat handlers so the effect below doesn't
 49→  // depend on unstable function references (which would cause an infinite
 50→  // render loop: new fn refs → effect fires → setSidebarHandlers → zustand
 51→  // update → AppShell re-renders → ChatPage re-renders → new fn refs → …).
 52→  const chatRef = useRef(chat);
 53→  chatRef.current = chat;
 54→
 55→  // Register sidebar handlers so the shell sidebar can interact with chat
 56→  useEffect(() => {
 57→    setSidebarHandlers({
 58→      activeConversationId: chat.activeConversationId,
 59→      isLoading: chat.isLoading,
 60→      onNewConversation: () => chatRef.current.onNewConversation(),
 61→      onSelectConversation: (id: string) => chatRef.current.onSelectConversation(id),
 62→    });
 63→  }, [chat.activeConversationId, chat.isLoading]);
 64→
 65→  // Cleanup sidebar handlers on unmount
 66→  useEffect(() => {
 67→    return () => {
 68→      setSidebarHandlers(undefined);
 69→    };
 70→  }, []);
 71→
 72→  return (
 73→    <section className="reachat-page">
 74→      {chat.pendingFile ? (
 75→        <div className="workspace-toolbar">
 76→          <div className="pending-file">
 77→            Attached: {chat.pendingFile.name}
 78→            <button type="button" onClick={() => chat.onUploadFile(undefined as unknown as File)}>
 79→              Clear
 80→            </button>
 81→          </div>
 82→        </div>
 83→      ) : undefined}
 84→
 85→      {(chat.discussEntity ?? chat.conversationDiscussEntity) ? (
 86→        <DiscussEntityCard
 87→          entity={(chat.discussEntity ?? chat.conversationDiscussEntity) as DiscussEntitySummary}
 88→        />
 89→      ) : undefined}
 90→
 91→      <div className="chat-main">
 92→        <Chat
 93→          viewType="chat"
 94→          theme={darkChatTheme}
 95→          sessions={chat.sessions}
 96→          activeSessionId={chat.activeSession.id}
 97→          components={chatComponentCatalog}
 98→          isLoading={chat.isLoading}
 99→          onSendMessage={chat.onSendMessage}
100→          onStopMessage={chat.onStopMessage}
101→          onFileUpload={chat.onUploadFile}
102→        >
103→          <SessionMessagePanel>
104→            <SessionMessages>
105→              {(conversations) =>
106→                conversations.map((conversation, index) => {
107→                  const isInherited = chat.inheritedMessageIds.has(conversation.id);
108→                  const isLastInherited = isInherited
109→                    && index < conversations.length - 1
110→                    && !chat.inheritedMessageIds.has(conversations[index + 1].id);
111→                  return (
112→                    <div
113→                      key={conversation.id}
114→                      data-message-id={conversation.id}
115→                      className={isInherited ? "message-inherited" : undefined}
116→                    >
117→                      <SessionMessage
118→                        conversation={conversation}
119→                        isLast={index === conversations.length - 1}
120→                      />
121→                      {!isInherited && conversation.response && onboardingState === "complete" ? (
122→                        <button
123→                          type="button"
124→                          className="branch-message-btn"
125→                          onClick={() => void chat.onBranchFromMessage(conversation.id)}
126→                          disabled={chat.isLoading || chat.branchingFromId !== undefined}
127→                          title="Branch from here"
128→                        >
129→                          <svg width="16" height="16" viewBox="0 0 16 16" fill="none" xmlns="http://www.w3.org/2000/svg" aria-hidden="true">
130→                            <path d="M5 3v4.5c0 1.1.9 2 2 2h2.5M5 3L3 5M5 3l2 2M11 5v4.5c0 1.1-.9 2-2 2H6.5M11 5l-2-2M11 5l2-2" stroke="currentColor" strokeWidth="1.5" strokeLinecap="round" strokeLinejoin="round"/>
131→                          </svg>
132→                        </button>
133→                      ) : undefined}
134→                      {isLastInherited ? (
135→                        <div className="branch-divider">Branch point</div>
136→                      ) : undefined}
137→                    </div>
138→                  );
139→                })
140→              }
141→            </SessionMessages>
142→            <ChatSuggestions
143→              suggestions={chat.suggestions}
144→              onSuggestionClick={(suggestion) => {
145→                void chat.onSendMessage(suggestion);
146→              }}
147→            />
148→            {onboardingState === "summary_pending" ? (
149→              <div className="onboarding-action-buttons">
150→                <button
151→                  type="button"
152→                  disabled={chat.isLoading}
153→                  onClick={() =>
154→                    void chat.onSendMessage("Looks good, let's go.", {
155→                      onboardingAction: "finalize_onboarding",
156→                    })}
157→                >
158→                  Looks good, let's go
159→                </button>
160→                <button
161→                  type="button"
162→                  disabled={chat.isLoading}
163→                  onClick={() =>
164→                    void chat.onSendMessage("I want to add more.", {
165→                      onboardingAction: "continue_onboarding",
166→                    })}
167→                >
168→                  I want to add more
169→                </button>
170→              </div>
171→            ) : undefined}
172→            <div onClickCapture={chat.onChatInputClickCapture}>
173→              <ChatInput
174→                ref={chat.chatInputRef}
175→                placeholder="Discuss tasks, decisions, and questions..."
176→                allowedFiles={[".md", ".txt"]}
177→                mentions={{
178→                  onSearch: chat.searchMentions,
179→                }}
180→                commands={{
181→                  items: COMMAND_ITEMS,
182→                }}
