  1→import { createOpenRouter } from "@openrouter/ai-sdk-provider";
  2→import { evalite } from "evalite";
  3→import { Factuality } from "autoevals";
  4→import { Surreal } from "surrealdb";
  5→import { afterAll, beforeAll } from "vitest";
  6→import { runAnalyticsAgent, type AnalyticsAgentOutput } from "../app/src/server/agents/analytics/agent";
  7→import type { ChatToolExecutionContext } from "../app/src/server/chat/tools/types";
  8→import { RecordId } from "surrealdb";
  9→import {
 10→  type EvalRuntime,
 11→  setupEvalRuntime,
 12→  teardownEvalRuntime,
 13→} from "./eval-test-kit";
 14→import { seedAnalyticsTestData, type AnalyticsSeedResult } from "./analytics-seed-data";
 15→
 16→type AnalyticsTestCase = {
 17→  id: string;
 18→  question: string;
 19→  /** Deterministic substring checks — use for values the model cannot paraphrase (numbers, proper nouns). */
 20→  expectedAnswerContains?: string[];
 21→  expectedAnswerNotContains?: string[];
 22→  /** Ground truth for LLM factuality check — use when the model may paraphrase. */
 23→  expectedFacts?: string;
 24→};
 25→
 26→type AnalyticsEvalOutput = {
 27→  caseId: string;
 28→  question: string;
 29→  answer: string;
 30→  query_executed: string;
 31→  result_summary: string;
 32→  success: boolean;
 33→  error?: string;
 34→};
 35→
 36→const analyticsModelId = process.env.ANALYTICS_MODEL;
 37→if (!analyticsModelId) {
 38→  throw new Error("ANALYTICS_MODEL env var is required for analytics evals");
 39→}
 40→
 41→let runtime: EvalRuntime;
 42→let seedResult: AnalyticsSeedResult;
 43→let analyticsSurreal: Surreal;
 44→let analyticsAgentModel: any;
 45→
 46→const surrealUrl = process.env.SURREAL_URL ?? "ws://127.0.0.1:8000/rpc";
 47→
 48→beforeAll(async () => {
 49→  try {
 50→    runtime = await setupEvalRuntime("analytics");
 51→    seedResult = await seedAnalyticsTestData(runtime.surreal);
 52→
 53→    // Create read-only analytics connection in the eval namespace
 54→    analyticsSurreal = new Surreal();
 55→    await analyticsSurreal.connect(surrealUrl);
 56→    await analyticsSurreal.signin({
 57→      namespace: runtime.namespace,
 58→      database: runtime.database,
 59→      username: "analytics",
 60→      password: "brain-analytics-readonly",
 61→    });
 62→    await analyticsSurreal.use({ namespace: runtime.namespace, database: runtime.database });
 63→
 64→    const openrouter = createOpenRouter({ apiKey: process.env.OPENROUTER_API_KEY! });
 65→    analyticsAgentModel = openrouter(analyticsModelId, {
 66→      plugins: [{ id: "response-healing" }],
 67→    });
 68→  } catch (error) {
 69→    console.error("beforeAll setup failed:", error);
 70→    throw error;
 71→  }
 72→}, 120_000);
 73→
 74→afterAll(async () => {
 75→  await analyticsSurreal?.close().catch(() => undefined);
 76→  await teardownEvalRuntime(runtime);
 77→}, 120_000);
 78→
 79→const cases: AnalyticsTestCase[] = [
 80→  {
 81→    id: "count-open-tasks",
 82→    question: "How many open tasks are there?",
 83→    expectedAnswerContains: ["5"],
 84→  },
 85→  {
 86→    id: "count-tasks-by-status",
 87→    question: "How many tasks are there in each status?",
 88→    expectedAnswerContains: ["open", "closed", "blocked"],
 89→  },
 90→  {
 91→    id: "stale-decisions",
 92→    question: "Which decisions have been provisional for over 2 weeks?",
 93→    expectedAnswerContains: ["JWT", "PostgreSQL"],
 94→  },
 95→  {
 96→    id: "open-observations",
 97→    question: "What are the open observations?",
 98→    expectedFacts: "There are 2 open observations: one about auth and billing timelines potentially conflicting (warning severity), and one about the dashboard feature lacking acceptance criteria (info severity).",
 99→  },
100→  {
101→    id: "dependency-chains",
102→    question: "Which tasks have dependencies on other tasks?",
103→    expectedFacts: "2 tasks have actual dependencies: 'Build invoice generator' depends on 'Integrate payment gateway', and 'Integrate payment gateway' depends on 'Setup CI pipeline'. The remaining tasks matched the query but have empty dependency lists.",
104→  },
105→  {
106→    id: "empty-result",
107→    question: "Are there any cross-project conflicts between decisions?",
108→    expectedAnswerContains: ["no"],
109→    expectedAnswerNotContains: ["there are conflicts", "there is a conflict", "conflicts exist"],
110→  },
111→];
112→
113→evalite<AnalyticsTestCase, AnalyticsEvalOutput, AnalyticsTestCase>("Analytics Agent Query Correctness", {
114→  data: cases.map((testCase) => ({ input: testCase, expected: testCase })),
115→  task: async (input) => runAnalyticsCase(input),
116→  scorers: [
117→    {
118→      name: "query-executes",
119→      description: "Did the agent produce a successful result without errors?",
120→      scorer: ({ output }) => (output.success ? 1 : 0),
121→    },
122→    {
123→      name: "answer-contains-expected",
124→      description: "Does the answer contain all expected substrings?",
125→      scorer: ({ output, expected }) => {
126→        if (!expected?.expectedAnswerContains || expected.expectedAnswerContains.length === 0) return 1;
127→        const lowerAnswer = output.answer.toLowerCase();
128→        const matches = expected.expectedAnswerContains.filter((s) =>
129→          lowerAnswer.includes(s.toLowerCase()),
130→        );
131→        return matches.length / expected.expectedAnswerContains.length;
132→      },
133→    },
134→    {
135→      name: "factuality",
136→      description: "LLM judge: is the answer factually consistent with the expected ground truth?",
137→      scorer: async ({ output, expected }) => {
138→        if (!expected?.expectedFacts) return 1;
139→        const result = await Factuality({
140→          input: expected.question,
141→          output: output.answer,
142→          expected: expected.expectedFacts,
143→        });
144→        const score = result.score ?? 0;
145→        // Factuality scores: A=0.4 (subset), B=0.6 (superset), C=1.0 (exact), D=0 (disagree), E=1.0 (equivalent)
146→        // A superset answer (B=0.6) is correct for our use case — the agent included extra detail.
147→        // Treat subset (A) and superset (B) as passing, only fail on disagreement (D=0).
148→        return score >= 0.4 ? 1 : 0;
149→      },
150→    },
151→    {
152→      name: "no-hallucination",
153→      description: "Answer does not contain forbidden substrings",
154→      scorer: ({ output, expected }) => {
155→        if (!expected?.expectedAnswerNotContains || expected.expectedAnswerNotContains.length === 0) return 1;
156→        const lowerAnswer = output.answer.toLowerCase();
157→        const violations = expected.expectedAnswerNotContains.filter((s) =>
158→          lowerAnswer.includes(s.toLowerCase()),
159→        );
160→        return violations.length === 0 ? 1 : 0;
161→      },
162→    },
163→  ],
164→  columns: ({ input, output, scores }) => [
165→    { label: "Model", value: analyticsModelId },
166→    { label: "Case", value: input.id },
167→    { label: "Success", value: output.success ? "yes" : "no" },
168→    { label: "Executes", value: formatScore(scores, "query-executes") },
169→    { label: "Contains", value: formatScore(scores, "answer-contains-expected") },
170→    { label: "Factual", value: formatScore(scores, "factuality") },
171→    { label: "NoHalluc", value: formatScore(scores, "no-hallucination") },
172→  ],
173→});
174→
175→function formatScore(scores: Array<{ name: string; score: number | null }>, name: string): string {
176→  const match = scores.find((s) => s.name === name);
177→  return match?.score !== null && match?.score !== undefined ? match.score.toFixed(2) : "N/A";
178→}
179→
180→async function runAnalyticsCase(testCase: AnalyticsTestCase): Promise<AnalyticsEvalOutput> {
181→  const context: ChatToolExecutionContext = {
182→    actor: "analytics_agent",
183→    workspaceRecord: seedResult.workspaceRecord,
184→    conversationRecord: new RecordId("conversation", "eval-analytics"),
185→    currentMessageRecord: new RecordId("message", `eval-${testCase.id}`),
186→    latestUserText: testCase.question,
187→  };
188→
189→  try {
190→    const result = await runAnalyticsAgent({
191→      analyticsSurreal,
192→      analyticsAgentModel,
193→      context,
194→      question: testCase.question,
195→    });
196→
197→    return {
198→      caseId: testCase.id,
199→      question: testCase.question,
200→      answer: result.answer,
201→      query_executed: result.query_executed,
202→      result_summary: result.result_summary,
203→      success: true,
204→    };
205→  } catch (error) {
206→    return {
207→      caseId: testCase.id,
208→      question: testCase.question,
209→      answer: "",
210→      query_executed: "",
211→      result_summary: "",
212→      success: false,
213→      error: error instanceof Error ? error.message : String(error),
214→    };
215→  }
216→}
217→

