473→DEFINE FUNCTION fn::entity_neighbors($entity: record) {
474→  RETURN SELECT
475→    ->entity_relation->(workspace, project, person, feature, task, decision, question) AS outgoing,
476→    <-entity_relation<-(workspace, project, person, feature, task, decision, question) AS incoming
477→  FROM $entity;
478→};
