 4→
 5→export function createAnalyticsTools(analyticsSurreal: Surreal) {
 6→  return {
 7→    execute_analytics_query: tool({
 8→      description:
 9→        "Execute a read-only SurrealQL SELECT query against the knowledge graph. Use parameterized queries ($param syntax) for any dynamic values. Always include a LIMIT clause.",
10→      inputSchema: z.object({
11→        intent: z.string().min(1).describe("What you are trying to learn from this query"),
12→        query: z.string().min(1).describe("The SurrealQL SELECT query to execute"),
13→        parameters: z
14→          .record(z.string(), z.unknown())
15→          .optional()
16→          .describe("Query parameters as key-value pairs, referenced as $key in the query"),
17→      }),
18→      execute: async (input) => {
19→        console.log("[analytics] query:", input.query);
20→        if (input.parameters) console.log("[analytics] params:", JSON.stringify(input.parameters));
21→        try {
22→          const result = await analyticsSurreal.query(input.query, input.parameters ?? {});
23→          const rows = Array.isArray(result) ? result.flat() : [result];
24→          console.log("[analytics] result: %d rows", rows.length, JSON.stringify(rows).slice(0, 500));
25→          return {
26→            success: true as const,
27→            result: rows,
28→            row_count: rows.length,
29→          };
30→        } catch (error) {
31→          console.log("[analytics] error:", error instanceof Error ? error.message : String(error));
32→          return {
33→            success: false as const,
34→            error: error instanceof Error ? error.message : String(error),
35→          };
36→        }
37→      },
38→    }),
39→  };
40→}
