 97→async function acceptWorkItem(
 98→  workspaceId: string,
 99→  item: WorkItemSuggestionProps,
100→): Promise<{ entityId: string }> {
101→  const response = await fetch(`/api/workspaces/${workspaceId}/work-items/accept`, {
102→    method: "POST",
103→    headers: { "Content-Type": "application/json" },
104→    body: JSON.stringify({
105→      kind: item.kind,
106→      title: item.title,
107→      rationale: item.rationale,
108→      ...(item.project ? { project: item.project } : {}),
109→      ...(item.priority ? { priority: item.priority } : {}),
110→      ...(item.category ? { category: item.category } : {}),
111→    }),
112→  });
113→  if (!response.ok) {
114→    throw new Error(`accept failed: ${response.status}`);
115→  }
116→  return response.json();
