 1→import { ToolLoopAgent, Output, stepCountIs } from "ai";
 2→import { z } from "zod";
 3→import type { Surreal } from "surrealdb";
 4→import type { ChatToolExecutionContext } from "../../chat/tools/types";
 5→import { buildAnalyticsSystemPrompt } from "./prompt";
 6→import { createAnalyticsTools } from "./tools";
 7→
 8→const entityRefSchema = z.object({
 9→  entityId: z.string().describe("Entity identifier in table:id format, e.g. 'task:abc123'."),
10→  kind: z.string().describe("Entity type: project, feature, task, decision, question, person, or observation."),
11→  name: z.string().describe("Display name of the entity."),
12→  status: z.string().describe("Current status of the entity, e.g. 'open', 'closed', 'confirmed'."),
13→});
14→
15→const analyticsResultSchema = z.object({
16→  answer: z.string().min(1).describe("Human-readable answer to the user's question. Write in natural language, not raw data."),
17→  query_executed: z.string().describe("The SurrealQL query that was executed to obtain the result."),
18→  result_summary: z.string().describe("Brief human-readable summary of the query results, e.g. '3 tasks found' or 'total of 12 features across 2 projects'."),
19→  referenced_entities: z.array(entityRefSchema).describe("Entities found in query results. Copy these verbatim from the tool result's referenced_entities field."),
20→});
21→
22→export type AnalyticsAgentOutput = z.infer<typeof analyticsResultSchema>;
23→
24→export type AnalyticsAgentInput = {
25→  analyticsSurreal: Surreal;
26→  analyticsAgentModel: any;
27→  context: ChatToolExecutionContext;
28→  question: string;
29→};
30→
31→export async function runAnalyticsAgent(input: AnalyticsAgentInput): Promise<AnalyticsAgentOutput> {
32→  const system = buildAnalyticsSystemPrompt();
33→
34→  const agent = new ToolLoopAgent({
35→    id: "analytics-agent",
36→    model: input.analyticsAgentModel,
37→    instructions: system,
38→    tools: createAnalyticsTools(input.analyticsSurreal),
39→    output: Output.object({ schema: analyticsResultSchema }),
40→    experimental_context: input.context,
41→    stopWhen: stepCountIs(5),
42→  });
43→
44→  const result = await agent.generate({
45→    prompt: input.question,
46→  });
47→
48→  if (!result.output) {
49→    throw new Error("analytics agent did not produce structured output");
50→  }
51→
52→  console.log("[analytics] answer:", result.output.answer);
53→  console.log("[analytics] result_summary:", result.output.result_summary);
54→
55→  return result.output;
56→}
