export const runGraphAwareChat = runChatAgent;

type EntityCardProps = {
  kind: string;
  name: string;
  entityId: string;
  confidence: number;
  status: string;
};

/**
 * Build EntityCard props from analytics entity refs and context entities
 * whose names appear in the response text.
 */
function buildEntityCards(
  responseText: string,
  context: ChatContext,
  analyticsRefs: EntityRef[],
): EntityCardProps[] {
  const seen = new Set<string>();
  const cards: EntityCardProps[] = [];

  // 1. Analytics tool entity refs (already structured, always include)
  for (const ref of analyticsRefs) {
    if (seen.has(ref.entityId)) continue;
    seen.add(ref.entityId);
    cards.push({
      kind: ref.kind,
      name: ref.name,
      entityId: ref.entityId,
      confidence: 1,
      status: ref.status ?? "unknown",
    });
  }

  // 2. Context entities matched by name in the response text
