 95→type WorkItemStatus = "pending" | "accepting" | "accepted" | "dismissed";
 96→
 97→async function acceptWorkItem(
 98→  workspaceId: string,
 99→  item: WorkItemSuggestionProps,
100→): Promise<{ entityId: string }> {
101→  const response = await fetch(`/api/workspaces/${workspaceId}/work-items/accept`, {
102→    method: "POST",
103→    headers: { "Content-Type": "application/json" },
104→    body: JSON.stringify({
105→      kind: item.kind,
106→      title: item.title,
107→      rationale: item.rationale,
108→      ...(item.project ? { project: item.project } : {}),
109→      ...(item.priority ? { priority: item.priority } : {}),
110→      ...(item.category ? { category: item.category } : {}),
111→    }),
112→  });
113→  if (!response.ok) {
114→    throw new Error(`accept failed: ${response.status}`);
115→  }
116→  return response.json();
117→}
118→
119→function WorkItemSuggestion(props: WorkItemSuggestionProps) {
120→  const workspaceId = useWorkspaceState((s) => s.workspaceId);
121→  const [status, setStatus] = useState<WorkItemStatus>("pending");
122→
123→  async function handleAccept() {
124→    if (!workspaceId || status !== "pending") return;
125→    setStatus("accepting");
126→    try {
127→      await acceptWorkItem(workspaceId, props);
128→      setStatus("accepted");
129→    } catch {
130→      setStatus("pending");
131→    }
132→  }
133→
134→  function handleDismiss() {
135→    setStatus("dismissed");
136→  }
137→
138→  if (status === "dismissed") return undefined;
139→
140→  const isDuplicate = props.possibleDuplicateId !== undefined;
141→
142→  return (
143→    <article className={`work-item-suggestion ${status === "accepted" ? "work-item-suggestion--accepted" : ""}`}>
144→      <div className="work-item-suggestion-header">
145→        <div style={{ display: "flex", alignItems: "center", gap: "0.3rem" }}>
146→          <span className="entity-kind">{props.kind === "task" ? "Task" : "Feature"}</span>
147→          {props.category ? <CategoryBadge category={props.category} /> : undefined}
148→          {props.priority ? <span className="work-item-priority">{props.priority}</span> : undefined}
149→        </div>
150→        {status === "accepted" ? (
151→          <span className="work-item-accepted-badge">Accepted</span>
152→        ) : (
153→          <div className="work-item-actions">
154→            <button
155→              type="button"
156→              className="work-item-btn work-item-btn--accept"
157→              onClick={handleAccept}
158→              disabled={status === "accepting"}
159→            >
160→              {status === "accepting" ? "..." : "Accept"}
161→            </button>
162→            <button
163→              type="button"
164→              className="work-item-btn work-item-btn--dismiss"
165→              onClick={handleDismiss}
166→            >
167→              Dismiss
168→            </button>
169→          </div>
170→        )}
171→      </div>
172→      <p className="entity-name">{props.title}</p>
173→      <p className="work-item-rationale">{props.rationale}</p>
174→      {isDuplicate ? (
175→        <p className="work-item-duplicate-hint">
176→          Similar to existing: {props.possibleDuplicateName} ({((props.possibleDuplicateSimilarity ?? 0) * 100).toFixed(0)}% match)
177→        </p>
178→      ) : undefined}
179→      {props.project ? <p className="work-item-project">Project: {props.project}</p> : undefined}
180→    </article>
181→  );
182→}
183→
184→function WorkItemSuggestionList(props: WorkItemSuggestionListProps) {
185→  const workspaceId = useWorkspaceState((s) => s.workspaceId);
186→  const [allStatus, setAllStatus] = useState<"idle" | "accepting">("idle");
187→  const [dismissedAll, setDismissedAll] = useState(false);
188→
189→  async function handleAcceptAll() {
190→    if (!workspaceId || allStatus === "accepting") return;
191→    setAllStatus("accepting");
192→    try {
193→      await Promise.all(props.items.map((item) => acceptWorkItem(workspaceId, item)));
194→    } catch {
195→      // individual items handle their own state
196→    }
197→    setAllStatus("idle");
198→  }
199→
200→  function handleDismissAll() {
201→    setDismissedAll(true);
202→  }
203→
204→  if (dismissedAll) return undefined;
205→
206→  return (
207→    <section className="work-item-suggestion-list">
208→      <div className="work-item-suggestion-list-header">
209→        <p className="extraction-summary-title">{props.title}</p>
210→        <div className="work-item-actions">
211→          <button
212→            type="button"
213→            className="work-item-btn work-item-btn--accept"
214→            onClick={handleAcceptAll}
215→            disabled={allStatus === "accepting"}
216→          >
217→            {allStatus === "accepting" ? "Accepting..." : "Accept All"}
218→          </button>
219→          <button
220→            type="button"
221→            className="work-item-btn work-item-btn--dismiss"
222→            onClick={handleDismissAll}
223→          >
224→            Dismiss All
225→          </button>
226→        </div>
227→      </div>
228→      <div className="extraction-summary-grid">
229→        {props.items.map((item) => (
230→          <WorkItemSuggestion key={`${item.kind}:${item.title}`} {...item} />
231→        ))}
232→      </div>
233→    </section>
234→  );
235→}
