import type { AnchorHTMLAttributes, ReactNode } from "react";
import { useViewState } from "../../stores/view-state";

const ENTITY_PROTOCOL = "entity://";

const kindLabels: Record<string, string> = {
  project: "Project",
  feature: "Feature",
  task: "Task",
  decision: "Decision",
  question: "Question",
  person: "Person",
  observation: "Observation",
};

/**
 * Renders entity:// links as styled inline entity references.
 * Falls through to a regular <a> for all other links.
 */
export function EntityLink(props: AnchorHTMLAttributes<HTMLAnchorElement> & { children?: ReactNode }) {
  const { href, children, ...rest } = props;
  const navigateToGraph = useViewState((s) => s.navigateToGraph);

  if (!href?.startsWith(ENTITY_PROTOCOL)) {
    return (
      <a href={href} {...rest}>
        {children}
      </a>
    );
  }

  const entityId = href.slice(ENTITY_PROTOCOL.length);
  const kind = entityId.split(":")[0];
  const label = kindLabels[kind];

  function handleClick(e: React.MouseEvent) {
    e.preventDefault();
    navigateToGraph(entityId);
  }

  return (
    <a
      href={href}
      onClick={handleClick}
      className="entity-link"
      title={label ? `${label} — view in graph` : "View in graph"}
      {...rest}
    >
      {label ? <span className="entity-link-kind">{label}</span> : undefined}
      {children}
    </a>
  );
}

/**
 * Markdown component override for reachat's `markdownComponents` prop.
 * Intercepts `<a>` elements and renders entity:// links as EntityLink.
 */
export const entityLinkMarkdownComponents = {
  a: EntityLink,
};

